package com.hiliving.content.news;
import jakarta.persistence.*;import java.time.Instant;
@Entity @Table(name="news") public class NewsEntity{@Id@GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(nullable=false,length=240)private String title;@Column(nullable=false,unique=true,length=260)private String slug;@Column(nullable=false,length=600)private String summary;@Column(nullable=false,columnDefinition="text")private String content;@Column(name="thumbnail_url",length=2048)private String thumbnailUrl;@Column(nullable=false)private boolean published;@Column(name="published_at")private Instant publishedAt;@Column(name="display_order",nullable=false)private int displayOrder;@Column(name="created_at",nullable=false,updatable=false)private Instant createdAt;@Column(name="updated_at",nullable=false)private Instant updatedAt;protected NewsEntity(){}static NewsEntity create(NewsRequest r){NewsEntity n=new NewsEntity();n.update(r);return n;}void update(NewsRequest r){title=r.title().trim();slug=r.slug();summary=r.summary().trim();content=r.content().trim();thumbnailUrl=clean(r.thumbnailUrl());published=r.published();publishedAt=r.publishedAt();displayOrder=r.sortOrder();}private static String clean(String v){return v==null||v.isBlank()?null:v.trim();}@PrePersist void create(){createdAt=Instant.now();updatedAt=createdAt;}@PreUpdate void updateTime(){updatedAt=Instant.now();}public Long getId(){return id;}public String getTitle(){return title;}public String getSlug(){return slug;}public String getSummary(){return summary;}public String getContent(){return content;}public String getThumbnailUrl(){return thumbnailUrl;}public boolean isPublished(){return published;}public Instant getPublishedAt(){return publishedAt;}public int getDisplayOrder(){return displayOrder;}public Instant getCreatedAt(){return createdAt;}public Instant getUpdatedAt(){return updatedAt;}}
